mapper.select:
SELECT co.id, co.org_id, co.clinic_id, c.clinic_name, co.charge_no, co.patient_id, p.patient_name, co.medical_record_id, mr.record_no AS medical_record_no, co.total_amount, co.discount_amount, co.receivable_amount, co.paid_amount, co.arrears_amount, co.order_status, co.charge_time, co.remark FROM charge_order co LEFT JOIN clinic c ON c.id = co.clinic_id LEFT JOIN patient p ON p.id = co.patient_id LEFT JOIN medical_record mr ON mr.id = co.medical_record_id WHERE co.is_deleted = 0 AND co.org_id = #{orgId}
AND co.clinic_id IN
#{clinicId}
AND mr.doctor_id = #{staffId}
AND co.patient_id = #{query.patientId}
AND co.clinic_id = #{query.clinicId}
AND co.order_status = #{query.orderStatus}
AND co.charge_time >= #{query.chargeDateFrom}
AND co.charge_time < DATE_ADD(#{query.chargeDateTo}, INTERVAL 1 DAY)
AND ( co.charge_no LIKE CONCAT('%', #{query.keyword}, '%') OR p.patient_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.mobile LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY co.charge_time DESC, co.id DESC

SELECT co.id, co.org_id, co.clinic_id, c.clinic_name, co.charge_no, co.patient_id, p.patient_name, p.mobile AS patient_mobile, co.medical_record_id, mr.record_no AS medical_record_no, co.treatment_plan_id, co.cashier_id, cashier.staff_name AS cashier_name, co.total_amount, co.discount_amount, co.receivable_amount, co.paid_amount, co.arrears_amount, co.order_status, co.charge_time, co.settled_at, co.remark FROM charge_order co LEFT JOIN clinic c ON c.id = co.clinic_id LEFT JOIN patient p ON p.id = co.patient_id LEFT JOIN medical_record mr ON mr.id = co.medical_record_id LEFT JOIN staff cashier ON cashier.id = co.cashier_id WHERE co.id = #{id} AND co.org_id = #{orgId} AND co.is_deleted = 0
AND co.clinic_id IN
#{clinicId}
AND mr.doctor_id = #{staffId}
LIMIT 1
